mapper.select:
select

from sys_role
where deleted = 0

    and `status` = #{status}

and role_id in (
    select role_id from sys_user_role sur where sur.user_id = #{userId}
    union
    select role_id from sys_org_role sor join sys_user_org suo on suo.org_id = sor.org_id where suo.user_id =
    #{userId}
    union
    select role_id from sys_post_role spr join sys_user_post sup on sup.post_id = spr.post_id where sup.user_id =
    #{userId}
)
